// Simulates reading an SBOM (e.g. project-sbom.json)
// Replace this with a real file read / HTTP request to pull your actual SBOM.
const packages = [
  { package: "React", version: "18.2" },
  { package: "Axios", version: "1.7" },
  { package: "Bootstrap", version: "5.3" },
  { package: "Express", version: "4.19" },
  { package: "OpenSSL", version: "3.0" },
  { package: "Library XYZ", version: "2.1" }
];

return packages.map(p => ({ json: p }));

// Simulated Trivy/FOSSology scan: looks up the license for each package.
// Replace this lookup with a real call to Trivy (Execute Command) or a scanner API.
const licenseMap = {
  "React": "MIT",
  "Axios": "MIT",
  "Bootstrap": "MIT",
  "Express": "MIT",
  "OpenSSL": "Apache-2.0",
  "Library XYZ": "GPL-3.0"
};

return items.map(item => {
  const pkg = item.json.package;
  const license = licenseMap[pkg] || "Unknown";
  return { json: { ...item.json, license } };
});

// Compares each package's license against the company's allowed license policy.
const allowedLicenses = ["MIT", "Apache-2.0", "BSD", "BSD-3-Clause"];

return items.map(item => {
  const isAllowed = allowedLicenses.includes(item.json.license);
  return {
    json: {
      ...item.json,
      status: isAllowed ? "Allowed" : "Restricted"
    }
  };
});

// Aggregates results into a single compliance summary object.
const all = items;
const restricted = all.filter(i => i.json.status === "Restricted");
const allowedCount = all.length - restricted.length;

return [{
  json: {
    project: "Sample Project",
    packagesScanned: all.length,
    allowed: allowedCount,
    restricted: restricted.length,
    complianceStatus: restricted.length > 0 ? "FAILED" : "PASSED",
    violations: restricted.map(i => i.json),
    violationsFound: restricted.length > 0
  }
}];

